/** A ténylegesen, natívan lefordított felület-nyelvek. A többi nyelv ezekből
 *  öröklődik (gépi/hasonló nyelvi fallback) — a nyelvválasztó „(auto)"-ként jelzi. */
/**
 * A profil „válaszidő" mezője a seed-adatban magyar szabad-szöveg. A chat-fejlécben
 * viszont a felhasználó nyelvén kell megjelennie — ez a helper a ismert értékeket
 * lefordított, teljes mondattá képezi. Ismeretlen érték esetén üres (elrejtjük).
 */
export function localizeResponseTime(raw: string | null | undefined, lang: Lang): string {
  const r = (raw ?? "").toLowerCase();
  if (!r) return "";
  if (r.includes("egy órán") || r.includes("within an hour") || r.includes("sat")) return tr("rt_under_hour", lang);
  if (r.includes("néhány") || r.includes("pár") || r.includes("few hours") || r.includes("par sat")) return tr("rt_few_hours", lang);
  if (r.includes("napon") || r.includes("within a day") || r.includes("dana")) return tr("rt_within_day", lang);
  return tr("rt_few_hours", lang);
}

// A FELÜLET mind a 12 nyelven natívan le van fordítva. (A HIRDETÉS-TARTALOM
// — cím/leírás — 4 forrás-nyelvű + élő auto-fordítás; lásd a nyelvi jegyzetet.)
export const NATIVE_LANGS: Lang[] = ["hu", "me", "sr", "bs", "hr", "en", "es", "ru", "uk", "sq", "el", "tr"];
export const isNativeLang = (l: Lang): boolean => NATIVE_LANGS.includes(l);

// Ha egy nyelvre nincs saját fordítás, melyik nyelvből vegye a szöveget.
// A dél-szláv nyelvek (sr/bs/hr) a montenegrói szöveget használják (közel azonos).
const FALLBACK_SRC: Record<Lang, Lang> = {
  hu: "hu", me: "me", en: "en", ru: "ru",
  sr: "me", bs: "me", hr: "me",
  uk: "ru",
  sq: "en", el: "en", tr: "en", es: "en"
};

/** A dinamikus tartalom (hirdetés-szöveg) csak 4 nyelvű — ide képezzük a nyelvet. */
const CONTENT_SRC: Record<Lang, "hu" | "me" | "en" | "ru"> = {
  hu: "hu", me: "me", en: "en", ru: "ru",
  sr: "me", bs: "me", hr: "me", uk: "ru",
  sq: "en", el: "en", tr: "en", es: "en"
};
export function contentLang(lang: Lang): "hu" | "me" | "en" | "ru" {
  return CONTENT_SRC[lang] ?? "en";
}
/** Lokalizált szöveg (hirdetés cím/leírás) feloldása a felület nyelvére, fallbackkel. */
export function loc(obj: { hu: string; me: string; en: string; ru: string }, lang: Lang): string {
  return obj[contentLang(lang)];
}

