  lang_auto_badge: { hu: "auto", me: "auto", en: "auto", ru: "авто", sr: "auto", bs: "auto", hr: "auto", uk: "авто", sq: "auto", el: "αυτόμ.", tr: "oto", es: "auto" },
  lang_auto_note: { hu: "Az „auto”-jelölésű nyelvek gépi/hasonló nyelvi fordítással jelennek meg.", me: "Jezici označeni „auto” prikazuju se mašinskim/sličnim prevodom.", en: "Languages marked “auto” are shown via machine / closest-language translation.", ru: "Языки с пометкой «авто» показываются через машинный/близкий перевод.", sr: "Језици означени „auto” приказују се машинским/сличним преводом.", bs: "Jezici označeni „auto” prikazuju se mašinskim/sličnim prevodom.", hr: "Jezici označeni „auto” prikazuju se strojnim / prijevodom najbližeg jezika.", uk: "Мови з позначкою «авто» показуються через машинний / найближчий переклад.", sq: "Gjuhët e shënuara “auto” shfaqen përmes përkthimit makinerik / gjuhës më të afërt.", el: "Οι γλώσσες με την ένδειξη «αυτόμ.» εμφανίζονται μέσω αυτόματης / κοντινότερης-γλώσσας μετάφρασης.", tr: "“oto” olarak işaretli diller makine / en yakın dil çevirisiyle gösterilir.", es: "Los idiomas marcados como «auto» se muestran mediante traducción automática o del idioma más cercano." },
