  delete_account: { hu: "Fiók törlése", me: "Obriši nalog", en: "Delete account", ru: "Удалить аккаунт", sr: "Обриши налог", bs: "Obriši nalog", hr: "Obriši račun", uk: "Видалити акаунт", sq: "Fshi llogarinë", el: "Διαγραφή λογαριασμού", tr: "Hesabı sil", es: "Eliminar cuenta" },
  delete_account_desc: { hu: "A fiókod és minden adatod (hirdetések, üzenetek, kedvencek) véglegesen törlődik. Ez nem vonható vissza.", me: "Nalog i svi podaci se trajno brišu. Nepovratno.", en: "Your account and all data (listings, messages, favorites) are permanently deleted. This cannot be undone.", ru: "Аккаунт и все данные будут удалены навсегда. Отменить нельзя.", sr: "Налог и сви подаци (огласи, поруке, омиљено) трајно се бришу. Ово се не може опозвати.", bs: "Nalog i svi podaci se trajno brišu. Nepovratno.", hr: "Vaš račun i svi podaci (oglasi, poruke, favoriti) trajno se brišu. To se ne može poništiti.", uk: "Ваш акаунт і всі дані (оголошення, повідомлення, збережене) видаляються назавжди. Це неможливо скасувати.", sq: "Llogaria juaj dhe të gjitha të dhënat (shpalljet, mesazhet, të preferuarat) fshihen përgjithmonë. Kjo nuk mund të zhbëhet.", el: "Ο λογαριασμός σας και όλα τα δεδομένα (αγγελίες, μηνύματα, αγαπημένα) διαγράφονται οριστικά. Δεν αναιρείται.", tr: "Hesabınız ve tüm verileriniz (ilanlar, mesajlar, favoriler) kalıcı olarak silinir. Bu işlem geri alınamaz.", es: "Tu cuenta y todos los datos (anuncios, mensajes, favoritos) se eliminan de forma permanente. Esto no se puede deshacer." },
  delete_account_confirm: { hu: "Biztosan véglegesen törlöd a fiókod? Ez nem vonható vissza.", me: "Trajno obrisati nalog? Nepovratno.", en: "Permanently delete your account? This cannot be undone.", ru: "Удалить аккаунт навсегда? Отменить нельзя.", sr: "Трајно обрисати налог? Ово се не може опозвати.", bs: "Trajno obrisati nalog? Nepovratno.", hr: "Trajno obrisati vaš račun? To se ne može poništiti.", uk: "Видалити акаунт назавжди? Це неможливо скасувати.", sq: "Të fshihet përgjithmonë llogaria juaj? Kjo nuk mund të zhbëhet.", el: "Οριστική διαγραφή του λογαριασμού σας; Δεν αναιρείται.", tr: "Hesabınız kalıcı olarak silinsin mi? Bu işlem geri alınamaz.", es: "¿Eliminar tu cuenta de forma permanente? Esto no se puede deshacer." },
