  pricing_soon_toast: { hu: "A fizetés hamarosan élesedik — felvesszük veled a kapcsolatot.", me: "Plaćanje uskoro — javit ćemo se.", en: "Billing goes live soon — we'll be in touch.", ru: "Оплата скоро заработает — мы свяжемся с вами.", sr: "Плаћање ускоро — јавићемо се.", bs: "Plaćanje uskoro — javit ćemo se.", hr: "Naplata uskoro počinje — javit ćemo se.", uk: "Оплата запрацює скоро — ми зв'яжемося з вами.", sq: "Faturimi nis së shpejti — do të jemi në kontakt.", el: "Οι χρεώσεις ενεργοποιούνται σύντομα — θα επικοινωνήσουμε.", tr: "Ödeme yakında başlıyor — sizinle iletişime geçeceğiz.", es: "La facturación estará disponible pronto — nos pondremos en contacto." },
  pricing_private_note: { hu: "Magánszemély vagy? Adj fel akár 3 hirdetést teljesen ingyen — nincs szükség előfizetésre.", me: "Fizičko lice? Objavi do 3 oglasa besplatno — bez pretplate.", en: "A private seller? Post up to 3 listings for free — no subscription needed.", ru: "Частное лицо? Разместите до 3 объявлений бесплатно — без подписки.", sr: "Физичко лице? Објави до 3 огласа бесплатно — без претплате.", bs: "Fizičko lice? Objavi do 3 oglasa besplatno — bez pretplate.", hr: "Prodajete kao fizička osoba? Objavite do 3 oglasa besplatno — bez pretplate.", uk: "Приватний продавець? Розмістіть до 3 оголошень безкоштовно — без підписки.", sq: "Shitës privat? Publiko deri në 3 shpallje falas — pa nevojë për abonim.", el: "Ιδιώτης πωλητής; Αναρτήστε έως 3 αγγελίες δωρεάν — χωρίς συνδρομή.", tr: "Bireysel satıcı mısınız? 3 ilana kadar ücretsiz yayınlayın — abonelik gerekmez.", es: "¿Vendes como particular? Publica hasta 3 anuncios gratis — sin suscripción." },
  pricing_faq_title: { hu: "Gyakori kérdések", me: "Česta pitanja", en: "FAQ", ru: "Вопросы", sr: "Честа питања", bs: "Česta pitanja", hr: "Česta pitanja", uk: "Часті питання", sq: "Pyetjet e shpeshta", el: "Συχνές ερωτήσεις", tr: "SSS", es: "Preguntas frecuentes" },
  pricing_private_title: { hu: "Magánszemélyként", me: "Kao fizičko lice", en: "As a private seller", ru: "Как частное лицо", sr: "Као физичко лице", bs: "Kao fizičko lice", hr: "Kao fizička osoba", uk: "Як приватна особа", sq: "Si shitës privat", el: "Ως ιδιώτης πωλητής", tr: "Bireysel satıcı olarak", es: "Como particular" },
  pricing_private_sub: { hu: "Neked nem kell előfizetés. Adj fel ingyen, és ha szeretnéd, egy-egy hirdetést kiemelhetsz, hogy többen lássák.", me: "Nije potrebna pretplata. Objavljuj besplatno, a po želji istakni pojedini oglas.", en: "No subscription needed. Post for free, and optionally boost a listing so more people see it.", ru: "Подписка не нужна. Публикуйте бесплатно и при желании продвигайте объявление.", sr: "Није потребна претплата. Објављуј бесплатно, а по жељи истакни поједини оглас.", bs: "Nije potrebna pretplata. Objavljuj besplatno, a po želji istakni pojedini oglas.", hr: "Nije potrebna pretplata. Objavljujte besplatno, a po želji istaknite pojedini oglas da ga vidi više ljudi.", uk: "Підписка не потрібна. Публікуйте безкоштовно й за бажанням просувайте оголошення, щоб його побачило більше людей.", sq: "Nuk nevojitet abonim. Publiko falas dhe, sipas dëshirës, promovo një shpallje që ta shohin më shumë njerëz.", el: "Δεν χρειάζεται συνδρομή. Αναρτήστε δωρεάν και προαιρετικά προβάλετε μια αγγελία ώστε να τη δουν περισσότεροι.", tr: "Abonelik gerekmez. Ücretsiz yayınlayın, isterseniz bir ilanı öne çıkararak daha fazla kişiye ulaştırın.", es: "No necesitas suscripción. Publica gratis y, si quieres, destaca un anuncio para que lo vean más personas." },
